var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"막아라! 해자를 뛰어넘는 녀석들을 집중적으로 노려!","JPN":"阻止しろ！　堀を飛び越えるやつらを集中的に狙え！","ENG":"Stop them! Focus on getting the ones that are jumping over the moat!","TWN":"攔住它們！集中攻擊那些越過護城河的傢伙！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"대형 마물 접근 중!","JPN":"大型の魔物が接近中！","ENG":"A large monster is approaching!","TWN":"大型怪物正在接近！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"1열 방책, 상승 전개!","JPN":"1列防柵、上昇展開！","ENG":"Raise the first row of the barricades!","TWN":"第一排防線，升起展開！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"지금이다! 놈들의 움직임이 멈춘 틈에 대형에게 집중 사격해!!!","JPN":"今だ！　やつらの動きが止まっている間に大型に集中射撃しろ！","ENG":"NOW! Focus fire on the large one while the others can't move!","TWN":"就是現在！趁它們停下時集火大型目標！！！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"대형 마물 격파!!","JPN":"大型の魔物を撃破！！","ENG":"The large monster has been felled!","TWN":"大型怪物擊破！！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"잘 하고 있어! 이대로 계속 하는 거다!","JPN":"よくやった！　このまま続けるんだ！","ENG":"We're doing great! Let's keep at it!","TWN":"幹得好！繼續保持！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"상공에 날개 마물 출현!","JPN":"上空に翼のある魔物が出現！","ENG":"Winged monsters have appeared in the sky!","TWN":"空中出現有翅膀的怪物！"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"지상에서도 대형 다수가 한꺼번에 옵니다!","JPN":"地上からも大型が多数、一斉に迫ってきています！","ENG":"Multiple large monsters are charging toward us from the ground as well!","TWN":"地面上也有大量大型目標同時出現！"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"지금일세!","JPN":"今だ！","ENG":"NOW!","TWN":"就是現在！"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"지금이다! 아발론의 방벽을 가동해!","JPN":"今だ！　アバロンの防壁を稼働しろ！","ENG":"Activate the barrier of Avalon!","TWN":"就是現在！啟動阿瓦隆的屏障！"},"stage":{"bg":"ROOT_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"뛰어들던 녀석들이 날파리처럼 떨어져 나가는군요.","JPN":"飛び込んできたやつらがハエのように弾き飛んでますね。","ENG":"Look at them fall to the ground. Even the ones that were jumping.","TWN":"那些衝過來的傢伙像蒼蠅一樣掉下去了。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"고대 유물이라 제대로 작동하기만 바랐는데… 이정도로 강력한 성능일 줄이야.","JPN":"古代の遺物なのでちゃんと作動するか不安でしたが……これほど強力な性能を見せてくれるとは。","ENG":"I just hoped that this ancient relic would work properly... But I never imagined it would be this potent.","TWN":"我還擔心這件古代遺物能不能正常運作…沒想到性能竟然這麼強。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"우리들이 연구하는 것도, 결국 아발론 선조들의 기술이 원천일세.","JPN":"私たちが研究しているのも、結局はアバロン祖先の技術を元にしている。","ENG":"All of our research is ultimately based on the technology of the ancestors of Avalon.","TWN":"我們研究的東西，追根究柢也是阿瓦隆祖先的技術。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"성능은 의심할 필요가 없지.","JPN":"その性能は疑う余地もない。","ENG":"There is no need to doubt its strength.","TWN":"性能是毋庸置疑的。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"어엇?!","JPN":"ああっ！？","ENG":"What?!","TWN":"咦？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"땅이 흔들립니다…!","JPN":"地面が揺れています……！","ENG":"The ground is trembling...!","TWN":"地面在震動…！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"지진인가?","JPN":"地震か？","ENG":"Is it an earthquake?","TWN":"是地震嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"…지하일세! 아래를 조심하게!","JPN":"……地下だ！　下に注意しろ！","ENG":"...They are beneath us! Be careful of your feet!","TWN":"…是地下！小心下面！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"이럴 수가…! 역장을 피해서 땅을 파고 들어온다고…?!","JPN":"そんな……！　力場を避けて土の下を掘って来ただと……！？","ENG":"Unbelievable...! They dug a hole underground to avoid the stasis field...?!","TWN":"怎麼會…！竟然避開了力場，鑽進了地裡…？！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"놈들은 방벽의 중추를 노리는 걸세! 저게 파괴되면 차단막이 사라지고 말아!!","JPN":"やつらは防壁の中枢を狙っているのだ！　あれが破壊されれば遮断幕が消えてしまう！！","ENG":"The monsters are aiming for the barrier's center! The barrier will fall if they destroy it!!","TWN":"那些傢伙的目標是屏障的核心！如果那裡被破壞，屏障就會消失！！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"너무 빨라서 맞힐 수가 없습니다!","JPN":"早すぎて当てられません！","ENG":"They are too fast to hit, sir!","TWN":"太快了，沒辦法命中！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};